@function ms-grid($units, $ratio)
      $column-sum: 100%
      $grid-sum: 0%
      $column-ratio: $ratio
      $return: 0
      $column-short: false
      @if $ratio > 1
        $column-ratio: 1 / $ratio
      @if $scale-grid-style == traditional
        @for $i from 1 through $units
          $column-sum: ms($i, 100%, $column-ratio)
          $grid-sum: $column-sum + $grid-sum
          $return: $column-sum
          @if $grid-sum > 100%
            $return: 0%
            @if $column-short == false
              $column-short: $i
          @if $i == $columns
            @if $grid-sum < 100%
              $return: 100% - $grid-sum + $column-sum
          @if $column-short == $i
            $return: 100% - $grid-sum + $column-sum
      @if $scale-grid-style == incremental
        @for $i from 1 through $units
          $return: ms(-1, $column-sum, (1 / $column-ratio))
          $column-sum: $column-sum - $return
          $grid-sum: $return + $grid-sum
          @if $grid-sum > 100%
            $return: 0%
            @if $column-short == false
              $column-short: $i
          @if $i == $columns
            @if $grid-sum < 100%
              $return: $column-sum
          @if $column-short == $i
            $return: $column-sum
      @return $return

=grid($options: ())
  position: relative
  display: flex
  flex-direction: row
  flex-wrap: wrap
  box-sizing: border-box

  // Handle children
  & > *
    position: relative
    box-sizing: content-box
    flex-grow: 0
    flex-shrink: 0

    // Auto order
    @if $sassyAutoOrder == true
      +gridItemOrder(999999)
      @for $i from 1 through $sassyAutoOrderLength
        &:nth-child(#{$i})
          +gridItemOrder($i * 10)

  // Prepare options
  $defaults: (gutterCompensation: true, hideCompensation: true)
  $options: map-merge($defaults, $options)

  // Handle gutter
  $g: sassyParseGutter(map-get($options, gutterCompensation))
  margin: #{-(map-get($g, gt)) + 0px} #{-(map-get($g, gr)) + 0px} #{-(map-get($g, gb)) + 0px} #{-(map-get($g, gl)) + 0px}
  width: calc(100% + #{map-get($g, gl) + map-get($g, gr) + 0px})

  // Handle overflow
  @if map-get($options, hideCompensation) == true
    overflow: hidden
